/****** Object:  View [dbo].[vw_CustomerAppointments]    Script Date: 29/06/2026 9:38:35 CH ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[vw_CustomerAppointments] AS
SELECT
    a.AppointmentId,
    a.CustomerId,
    cu.FullName AS CustomerName,
    cu.Phone AS CustomerPhone,
    a.EmployeeId,
    eu.FullName AS EmployeeName,
    a.AppointmentDate,
    a.StartTime,
    a.EndTime,
    a.Status AS AppointmentStatus,
    i.InvoiceId,
    i.TotalAmount,
    i.DiscountAmount,
    i.FinalAmount,
    i.Status AS InvoiceStatus,
    p.PaymentId,
    p.Status AS PaymentStatus,
    p.PaymentMethod,
    rf.RefundId,
    rf.Status AS RefundStatus
FROM Appointments a
JOIN Customers c ON a.CustomerId = c.CustomerId
JOIN Users cu ON c.UserId = cu.UserId
JOIN Employees e ON a.EmployeeId = e.EmployeeId
JOIN Users eu ON e.UserId = eu.UserId
LEFT JOIN Invoices i ON a.AppointmentId = i.AppointmentId
OUTER APPLY (
    SELECT TOP 1 *
    FROM Payments p2
    WHERE p2.InvoiceId = i.InvoiceId
    ORDER BY p2.CreatedAt DESC, p2.PaymentId DESC
) p
OUTER APPLY (
    SELECT TOP 1 *
    FROM Refunds rf2
    WHERE rf2.PaymentId = p.PaymentId
    ORDER BY rf2.CreatedAt DESC, rf2.RefundId DESC
) rf;

GO
