INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (43, 1, N'Customer Churn Prediction', N'Phân tích rủi ro churn dựa trên dữ liệu khách hàng', N'{"summary":"Hầu hết danh sách khách hàng có dấu hiệu rủi ro cực kỳ cao do tỷ lệ hủy lịch (cancellation_count) bất thường và nhiều khách hàng mới chưa từng thực hiện dịch vụ thực tế.","customers":[{"customer_id":"2","name":"Khách hàng 01","risk_level":"HIGH_RISK","risk_score":90,"reason":["Chưa từng có lượt ghé thăm thực tế","Đã hủy lịch đặt duy nhất"],"recommended_action":["Gửi voucher giảm giá 20% để khuyến khích trải nghiệm lần đầu","Gửi Zalo giới thiệu các dịch vụ phổ biến"]},{"customer_id":"82","name":"Gia Kiên","risk_level":"MEDIUM_RISK","risk_score":50,"reason":["Tần suất hủy lịch rất cao (20 lần)","Tuy nhiên chi tiêu cao và đánh giá 5 sao"],"recommended_action":["Gọi điện chăm sóc khách hàng VIP để tìm hiểu lý do hủy lịch thường xuyên","Tặng gói combo dịch vụ chăm sóc da mặt để giữ chân"]},{"customer_id":"83","name":"Kien Duong","risk_level":"HIGH_RISK","risk_score":80,"reason":["Tỷ lệ hủy lịch cực kỳ cao (59 lần)","Có lịch sử no-show (vắng mặt không báo trước)"],"recommended_action":["Gọi điện xác nhận lịch hẹn trước 24h","Gửi tin nhắn nhắc nhở lịch hẹn qua Zalo"]},{"customer_id":"84","name":"Kiên Gia","risk_level":"HIGH_RISK","risk_score":95,"reason":["Chưa từng thực hiện dịch vụ","Hủy toàn bộ các lịch đặt"],"recommended_action":["Gửi ưu đãi dùng thử dịch vụ massage đá nóng miễn phí nhỏ","Liên hệ khảo sát nhu cầu khách hàng"]},{"customer_id":"85","name":"Kiên Dương","risk_level":"HIGH_RISK","risk_score":100,"reason":["Chưa từng thực hiện dịch vụ","Hủy lịch liên tục nhiều lần trong cùng một ngày"],"recommended_action":["Gửi mã giảm giá 20% cho lần đặt lịch đầu tiên","Kiểm tra lại tính xác thực của thông tin đặt lịch"]},{"customer_id":"86","name":"Gia Dương","risk_level":"HIGH_RISK","risk_score":95,"reason":["Chưa thực hiện dịch vụ","Tỷ lệ hủy lịch cao (8 lần)"],"recommended_action":["Gửi voucher giảm giá 15% cho dịch vụ Massage đá nóng","Nhắn tin chăm sóc nhắc quay lại"]}]}', N'gemini-2.5-flash', 1200, 800, CAST(0.0150 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T17:09:06.850' AS DateTime))
