INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (47, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan cân đối, đây là dáng mặt lý tưởng, phù hợp với hầu hết các kiểu tóc từ ngắn đến dài, dễ dàng tạo điểm nhấn mà không cần che khuyết điểm","hair_type":"Chất tóc tự nhiên với độ dày trung bình, có nền tảng tốt để thực hiện các kỹ thuật uốn hoặc nhuộm mà không lo quá mỏng hoặc quá cứng","skin_tone":"Tông da trung bình sáng với sắc độ ấm, phù hợp với các gam màu nóng, trung tính hoặc các tông màu trầm ấm để tôn lên sự rạng rỡ của làn da"},"recommendations":{"hairstyles":[{"name":"Layered Cut hiện đại","description":"Tạo các lớp tóc tỉa layer nhẹ nhàng giúp tăng độ phồng tự nhiên cho chất tóc trung bình và làm nổi bật đường nét cân đối của khuôn mặt trái xoan"},{"name":"Side Part vuốt rủ nhẹ","description":"Kiểu tóc thanh lịch, phù hợp với hình thể học khuôn mặt, mang lại vẻ ngoài chuyên nghiệp và hiện đại"}],"colors":[{"name":"Nâu Hạt Dẻ hoặc Nâu Đồng","description":"Những tông màu ấm này cực kỳ tôn da cho người có skin tone ấm, tạo cảm giác trẻ trung, sáng da và hài hòa với phong cách thời trang"}]},"trending":{"title":"Xu hướng tóc Nam tính hiện đại 2026","styles":["Textured Crop","Modern Mullet nhẹ"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng đã từng sử dụng và đánh giá 5/5 cho dịch vụ này, cho thấy sự hài lòng cao với trải nghiệm chăm sóc toàn diện. Việc gợi ý combo này giúp tối ưu hóa thời gian và tăng giá trị đơn hàng."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Khách hàng có lịch sử nhuộm tóc thời trang liên tục trong tháng 6, việc bổ sung liệu trình phục hồi là cần thiết để duy trì sức khỏe sợi tóc và giữ màu nhuộm bền hơn."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên về Hair Color và Hair Styling với đánh giá tuyệt đối 5/5, đồng thời là người đã thực hiện thành công các dịch vụ nhuộm và phục hồi cho khách hàng trước đây."},"marketing_insight":"Khách hàng Gia Kiên là khách hạng Gold với tần suất sử dụng dịch vụ cực kỳ cao (đặc biệt là các gói Detox và Massage). Khách có xu hướng ưa chuộng sự thư giãn toàn diện. Salon nên mời khách mua gói Thẻ thành viên VIP hoặc gói Combo chăm sóc định kỳ (Hair + Spa) để giữ chân khách hàng trung thành và tăng doanh thu dài hạn."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:05:00.077' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (48, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:05:36.490' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (49, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan cân đối, là dáng mặt lý tưởng có thể linh hoạt áp dụng hầu hết các kiểu tóc từ ngắn đến dài mà không cần che khuyết điểm","hair_type":"Chất tóc tự nhiên với độ dày trung bình, tạo điều kiện thuận lợi cho việc tạo phồng hoặc uốn định hình","skin_tone":"Tông da trung bình sáng với sắc độ ấm, phù hợp với các gam màu nóng, trung tính hoặc màu trầm ấm để tôn da"},"recommendations":{"hairstyles":[{"name":"Side Part hiện đại kết hợp uốn phồng","description":"Tận dụng khuôn mặt trái xoan để tạo điểm nhấn lịch lãm, uốn phồng phần đỉnh giúp tăng độ dày cho chất tóc trung bình"},{"name":"Layer ngắn tỉa layer","description":"Kiểu tóc trẻ trung, tạo sự chuyển động tự nhiên, phù hợp với chất tóc tự nhiên và dễ dàng chăm sóc hàng ngày"}],"colors":[{"name":"Nâu hạt dẻ hoặc Nâu ấm","description":"Các tông màu ấm này sẽ hòa quyện hoàn hảo với tông da trung bình sáng, mang lại vẻ ngoài khỏe khoắn và sang trọng"}]},"trending":{"title":"Xu hướng Men''s Grooming 2026","styles":["Textured Crop","Modern Mullet nhẹ nhàng"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng đã từng sử dụng combo này và đánh giá 5/5, cho thấy sự ưa chuộng đối với các gói dịch vụ kết hợp để tối ưu thời gian và trải nghiệm"},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Khách hàng có lịch sử nhuộm tóc thời trang nhiều lần trong thời gian ngắn (17, 18, 19/6), cần phục hồi chuyên sâu để duy trì sức khỏe sợi tóc"}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên môn cao về Hair Color và Hair Styling, đồng thời khách hàng đã từng đánh giá 5/5 cho dịch vụ phục hồi và combo do Stylist này thực hiện"},"marketing_insight":"Khách hàng Gia Kiên là thành viên hạng Gold, tần suất sử dụng dịch vụ rất cao và đa dạng (từ Hair, Skincare đến Detox). Khách có xu hướng thích các gói Combo và dịch vụ thư giãn. Salon nên mời khách nâng cấp lên gói Membership năm hoặc thẻ liệu trình chăm sóc tóc & da mặt định kỳ để giữ chân khách hàng trung thành."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:06:00.323' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (50, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan với tỷ lệ cân đối, là dáng mặt lý tưởng, dễ dàng phù hợp với hầu hết các kiểu tóc từ ngắn đến dài.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, tạo điều kiện thuận lợi cho việc uốn tạo phồng hoặc tạo kiểu mà không lo quá nặng hay quá mỏng.","skin_tone":"Tông da trung bình sáng với sắc độ ấm (warm tone), phù hợp với các gam màu trầm ấm hoặc trung tính để làm tôn lên độ sáng của làn da."},"recommendations":{"hairstyles":[{"name":"Side Part hiện đại","description":"Kiểu tóc này tôn lên sự cân đối của khuôn mặt trái xoan, tạo vẻ ngoài lịch lãm, chuyên nghiệp và dễ chăm sóc với chất tóc trung bình."},{"name":"Textured Crop","description":"Tạo độ phồng và kết cấu tự nhiên cho phần tóc trên, phù hợp với chất tóc tự nhiên của khách hàng, mang lại vẻ trẻ trung, năng động."}],"colors":[{"name":"Nâu Chocolate hoặc Nâu ấm","description":"Các tông màu nâu ấm sẽ hòa hợp tuyệt đối với skin tone ấm, tạo sự hài hòa, sang trọng và làm sáng da hơn so với màu đen truyền thống."}]},"trending":{"title":"Xu hướng Grooming Nam 2026","styles":["Quiet Luxury Haircut","Natural Texture Flow"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng từng sử dụng và đánh giá 5/5 cho combo này, cho thấy sự hài lòng cao với dịch vụ kết hợp. Việc nâng cấp lên combo sẽ tối ưu thời gian và trải nghiệm chăm sóc toàn diện."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Do lịch sử khách hàng thường xuyên nhuộm tóc thời trang (ngày 17, 18, 19/6), việc bổ sung liệu trình phục hồi sẽ giúp duy trì sức khỏe sợi tóc, tránh xơ rối do hóa chất."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên môn cao về Hair Styling và Hair Color, đồng thời là người từng thực hiện dịch vụ Phục hồi và Combo cho khách hàng với đánh giá tuyệt đối 5/5."},"marketing_insight":"Khách hàng Gia Kiên thuộc hạng Gold với tần suất ghé thăm salon rất dày đặc (hầu như mỗi ngày trong tháng 6), cho thấy mức độ trung thành và khả năng chi tiêu cao. Salon nên đề xuất gói thẻ thành viên Platinum hoặc gói Combo chăm sóc định kỳ (Hair & Body) để giữ chân khách hàng và tối ưu hóa doanh thu dài hạn."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:08:12.990' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (51, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:09:00.613' AS DateTime))
