INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (56, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan cân đối, là dáng mặt lý tưởng phù hợp với hầu hết các kiểu tóc từ ngắn đến dài và nhiều kiểu tạo phồng khác nhau.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, tạo điều kiện thuận lợi cho việc uốn tạo kiểu và nhuộm màu mà không quá lo ngại về việc tóc bị quá xẹp hoặc quá khó vào nếp.","skin_tone":"Tông da trung bình sáng với sắc độ ấm, phù hợp với các gam màu ấm, màu trung tính hoặc các tông màu trầm sang trọng để tôn lên độ sáng của da."},"recommendations":{"hairstyles":[{"name":"Side Part hiện đại kết hợp uốn phồng","description":"Tận dụng khuôn mặt trái xoan để tạo điểm nhấn với đường rẽ ngôi 7/3, uốn phồng nhẹ phần đỉnh để tăng vẻ nam tính và thanh lịch, phù hợp với chất tóc trung bình."},{"name":"Layer ngắn tỉa textured","description":"Kiểu tóc layer giúp tạo độ chuyển động tự nhiên, làm nổi bật sự cân đối của khuôn mặt và dễ dàng chăm sóc hàng ngày."}],"colors":[{"name":"Nâu hạt dẻ hoặc Nâu ấm (Warm Brown)","description":"Màu sắc này hòa hợp tuyệt vời với tông da ấm, mang lại vẻ ngoài trẻ trung nhưng vẫn đủ chuyên nghiệp và tinh tế."}]},"trending":{"title":"Xu hướng Grooming Nam 2026","styles":["Modern Mullet nhẹ","Textured Crop với hiệu ứng mờ"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng từng sử dụng Combo này và đánh giá 5/5, cho thấy sự hài lòng cao với việc chăm sóc toàn diện. Việc kết hợp cắt tóc, nhuộm và chăm sóc móng sẽ tối ưu hóa thời gian và trải nghiệm."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Vì khách hàng có lịch sử nhuộm tóc thời trang liên tục trong tháng 6, việc bổ sung liệu trình phục hồi là cần thiết để duy trì sức khỏe sợi tóc, tránh xơ rối sau hóa chất."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam là chuyên gia về Hair Styling và Hair Color với đánh giá tuyệt đối 5/5, đồng thời khách hàng đã từng làm dịch vụ Phục hồi tóc và Combo tóc với stylist này và đánh giá rất cao."},"marketing_insight":"Khách hàng Gia Kiên có tần suất ghé thăm salon cực kỳ cao (hầu như hàng ngày trong tháng 6) và sử dụng đa dạng dịch vụ từ Hair, Skincare đến Detox. Đây là khách hàng trung thành hạng Gold với chi tiêu lớn. Salon nên mời khách hàng nâng cấp lên gói Thẻ thành viên VIP hoặc gói Membership chăm sóc định kỳ (Monthly Package) bao gồm Cắt tóc + Massage + Detox để giữ chân khách hàng và tối ưu hóa doanh thu dài hạn."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:10:44.157' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (57, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:14:16.670' AS DateTime))
