INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (59, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan cân đối, là hình dáng lý tưởng cho phép thử nghiệm linh hoạt nhiều kiểu tóc từ ngắn đến dài mà không cần quá lo lắng về việc che khuyết điểm.","hair_type":"Chất tóc tự nhiên với độ dày trung bình, tạo nền tảng tốt để thực hiện các kỹ thuật uốn tạo phồng hoặc tạo kiểu mà không gây áp lực quá lớn lên sợi tóc.","skin_tone":"Tông da trung bình sáng với sắc độ ấm, phù hợp với các gam màu mang sắc vàng, đồng hoặc nâu ấm để làm tôn lên sự rạng rỡ của làn da."},"recommendations":{"hairstyles":[{"name":"Modern Quiff kết hợp Fade","description":"Kiểu tóc này tạo độ phồng ở đỉnh đầu, tôn vinh sự cân đối của khuôn mặt trái xoan và mang lại vẻ ngoài trẻ trung, lịch lãm."},{"name":"Side Part rủ hiện đại","description":"Phù hợp với chất tóc độ dày trung bình, tạo vẻ ngoài lãng tử và thanh thoát, tận dụng lợi thế khuôn mặt cân đối."}],"colors":[{"name":"Nâu hạt dẻ hoặc Nâu đồng","description":"Các tông màu ấm này sẽ hòa hợp tuyệt vời với skin tone ấm của khách hàng, tạo hiệu ứng da sáng và khỏe khoắn hơn."}]},"trending":{"title":"Xu hướng Men''s Grooming 2026","styles":["Textured Crop","Soft Mullet hiện đại"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng đã từng sử dụng combo này và đánh giá 5/5, cho thấy sự hài lòng cao với việc chăm sóc toàn diện. Việc nâng cấp lên combo này sẽ tối ưu thời gian và trải nghiệm."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Khách hàng có lịch sử nhuộm tóc thời trang liên tục trong tháng 6, vì vậy cần một liệu trình phục hồi chuyên sâu để đảm bảo sức khỏe sợi tóc sau hóa chất."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên về Hair Styling và Hair Color với đánh giá tuyệt đối 5/5, đồng thời là người đã thực hiện thành công dịch vụ Phục hồi tóc và Combo tóc & nail cho khách hàng trước đây."},"marketing_insight":"Khách hàng Gia Kiên là hạng Gold, có tần suất ghé thăm salon cực cao (gần như hàng ngày) và sử dụng đa dạng dịch vụ từ Hair, Skincare đến Detox. Đây là nhóm khách hàng trung thành lý tưởng để mời mua gói Member VIP năm hoặc gói Combo chăm sóc toàn diện (Hair-Skin-Body) theo tháng để tối ưu hóa chi phí cho khách và ổn định doanh thu cho salon."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:14:43.657' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (60, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:19:27.050' AS DateTime))
