INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (64, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan: Vừa phải, cân đối, phù hợp nhiều kiểu tóc. Kiểu tóc được khuyến nghị nên tôn vũ trụ, tạo sự thanh lịch và nhẹ nhàng.","hair_type":"Chất tóc tự nhiên, độ dày trung bình: Cần tăng độ bóng, độ dày thực tế bằng các dịch vụ phục hồi và chăm sóc tóc.","skin_tone":"Tông da trung bình sáng (tone ấm): Màu tóc vàng ngọt, hồng nhạt, và gỗ tự nhiên sẽ nhấn mạnh ánh sáng nhẹ của da."},"recommendations":{"hairstyles":[{"name":"Bob dài bề ngoài có lớp ruy rũ","description":"Độ dài vừa phải phù hợp với khuôn mặt trái xoan, tạo cảm giác phẳng và trâu hồ, phù hợp với tóc tự nhiên, dày trung bình."},{"name":"Lông lết trung bình, keratin smoothing","description":"Kích thích tăng độ bóng, tạo đường nét thanh lịch, giúp tóc dày hơn khi nhìn qua."}],"colors":[{"name":"Honey Blonde với gợi nhớ ánh nắng (vàng ngọt)","description":"Tông màu nhẹ, tỏa sáng ánh sáng ấm, nổi bật dựa trên tông da trung bình sáng."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026 - Tóc nhẹ lướt","styles":["Tóc dài nắp gương với lớp dư nhẹ","Tóc mái xoăn nhẹ"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Để tạo độ bồng bềnh và tạo độ bóng cho mái tóc, hỗ trợ tăng độ dày và sự tròn trịa, ăn khớp với kiểu bó Bob, và nâng cao giá trị dịch vụ."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Khách đã thường xuyên dùng dịch vụ màu và kiểm soát zèn làn tóc, cần phục hồi bằng collagen và keratin để tránh gãy rụng."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên Hair Styling và Hair Color với đánh giá 5/5, đã thực hiện thành công nhiều dịch vụ màu và uốn, phù hợp với khách hàng Gold."},"marketing_insight":"Khách đã chi tiêu nhiều vào các dịch vụ Massage và Detox trong tháng, nhưng chưa trải nghiệm đầy đủ combo cao cấp. Đề xuất gói thành viên Gold Keep‑Alive: 3 lần sắc đẹp + 2 lần chăm sóc tóc + ưu đãi 10% cho combo Uốn + Phục hồi, giúp khách tăng trung thành và chi tiêu trung bình 1.200.000đ/phiên. Ngoài ra, khuyến khích đăng ký thêm gói “Hair Care Home” để giữ độ bóng và phòng ngừa hư tổn, tăng 20% hành vi mua sắm mỗi 3 tháng."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:26:38.357' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (65, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:27:10.067' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (66, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan, dáng mặt cân đối, phù hợp với nhiều kiểu tóc đa dạng từ kiểu tóc ngắn, gọn gàng đến các kiểu tóc dài và biên giới.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, đã trải qua nhiều lần nhuộm và phục hồi, nên cần độ bền và độ ẩm cao.","skin_tone":"Tông da trung bình sáng (tone ấm), so sánh nên chọn màu tóc nhẹ nhàng, chiết tễ mềm mại để làm nổi bật cơ thể."},"recommendations":{"hairstyles":[{"name":"Cắt & Tạo Kiểu Tóc Layered Cut (ID 7)","description":"Kiểu tóc layered cut sẽ tạo độ thể tích và độ phong phú, khắc phục tình trạng tóc mỏng nhẹ và vừa phù hợp với hình dáng trái xoan, vừa dễ dàng bảo quản."},{"name":"Tóc Mid-Length Curly Hair (Uốn tóc setting, ID 9)","description":"Thiết lập uốn kiểu nhẹ chiều tạo độ puffy và rũ nhẹ, làm cho khuôn mặt trông sau mặt lộ rõ hơn và hài hòa với da sáng."}],"colors":[{"name":"Copper Blond (Iridescent Warm Tone, ID 8)","description":"Màu tóc copper blond nhẹ nhàng, pha trí ánh đỏ, thích hợp với tông da ấm và giúp đẩy lùi cảm giác mệt mỏi quan sát."}]},"trending":{"title":"Xu hướng tóc mùa Xuân 2026","styles":["Flip Back Parted Bangs","Boho Curls","Soft Bangs with Textured Layers"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Với lịch sử khách hàng Thích các dịch vụ Combo và đã nhận được đánh giá 5/5, combo sẽ tăng giá trị tổng trải nghiệm, cung cấp nail cao cấp và chăm sóc tóc tình trạng đã được phục hồi, đồng thời khuyến khích việc giữ được làn da sáng và tóc khỏe mạnh."},{"service_id":9,"service_name":"Uốn tóc setting","reason":"Thiết lập uốn giúp tóc mềm mượt và thêm độ volume, phù hợp với tóc đã từng bẩn trùng qua các lần nhuộm.  Đây là dịch vụ cao cấp giúp mang lại kiểu dáng thể hiện phong cách trưởng thành, đặc biệt hữu ích cho khách hàng Gold."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có chuyên môn sâu về Hair Styling và Hair Color, được đánh giá 5/5. Anh ấy đã dành nhiều thời gian với khách hàng trong các dịch vụ dye và úp, có thi thoảng Đạt điểm cao - chuyên gia phù hợp nhất cho nhu cầu uốn + nhuộm vàng cà vạt."},"marketing_insight":"Khách hàng hiện đang xuyên qua nhiều dịch vụ skincare và massage, không có lịch sử mua gói thẻ thành viên. Với mức loyalty Gold và sử dụng nhiều dịch vụ combo, salon nên mời Gia Kiên đăng ký gói thẻ VIP trị giá ưu đãi: 5% giảm giá mỗi 3 dịch vụ hoặc nhận 1 dịch vụ quy trình chăm sóc da nội bộ miễn phí khi đạt 2000 điểm. Điều này không chỉ tăng doanh thu mà còn giữ chân khách lâu dài, tạo điều kiện cho các dịch vụ cao cấp như Uốn, Nhuộm, và Combo nói trên."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:27:44.097' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (67, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan cân đối, phù hợp với nhiều kiểu tóc dài và trung bình, có thể tạo độ phồng hoặc lớp cắt để tôn lên đường cằm mềm mại.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, chưa có dấu hiệu hư tổn nặng nhưng đã trải qua nhiều lần nhuộm và cấy tinh chất phục hồi.","skin_tone":"Tông da trung bình sáng, tone ấm, giúp các màu tóc ấm như caramel, honey, hoặc tone nâu đỏ nổi bật."},"recommendations":{"hairstyles":[{"name":"Bob lớp nhẹ với mềm mại phía sau","description":"Kiểu bob dài tới vai với lớp cắt tầng nhẹ giúp tạo độ phồng cho mặt trái xoan, phù hợp với độ dày tóc trung bình và dễ duy trì."},{"name":"Lọn tóc mềm uốn xoăn nhẹ (soft waves)","description":"Uốn tóc setting tạo sóng nhẹ, tăng khối lượng và làm nổi bật đường cằm, thích hợp cho khách hàng muốn thay đổi phong cách mà không mất quá nhiều thời gian chăm sóc."}],"colors":[{"name":"Caramel Honey Blonde","description":"Màu ấm caramel pha chút vàng honey tôn lên tông da ấm, đồng thời tạo độ sáng cho tóc tự nhiên, phù hợp với nhu cầu làm mới màu tóc thời trang."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Soft Waves Kết Hợp Nhẹ Nhàng","Bob Lớp Nhiều Tầng"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã thường xuyên sử dụng dịch vụ tóc và đã có lịch sử cắt, nhuộm, cấy tinh chất. Combo giúp khách đồng thời làm mới màu tóc, phục hồi sức khỏe tóc (cấy tinh chất) và chăm sóc nail cao cấp, tăng giá trị đơn hàng lên 900.000đ."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Mặc dù tóc hiện tại chưa hư nặng, nhưng lịch sử nhuộm nhiều lần và cấy tinh chất cho thấy cần duy trì độ bóng và sức khỏe, dịch vụ này bổ trợ cho combo màu mới."}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có đánh giá 5/5, chuyên môn Hair Styling & Hair Color, đã thực hiện nhiều lần nhuộm và cắt cho khách, phù hợp nhất để thực hiện combo tóc và nail chất lượng cao."},"marketing_insight":"Khách hàng đang ở hạng Gold với 427 điểm, cho thấy mức chi tiêu ổn định và sẵn sàng đầu tư vào dịch vụ cao cấp. Salon nên đề xuất gói thành viên Gold Plus (tăng 10% điểm mỗi lần sử dụng) kèm ưu đãi giảm 15% cho combo tóc và nail, khuyến khích khách đặt lịch định kỳ hàng tháng cho phục hồi tóc và chăm sóc nail, tăng tần suất ghé thăm và giá trị trung bình mỗi lần tới."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:28:38.770' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (68, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:29:32.283' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (69, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:29:45.003' AS DateTime))
