INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (72, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (cân đối, phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (tone ấm)"},"recommendations":{"hairstyles":[{"name":"Cắt & tạo kiểu tóc “Bob cropped”","description":"Kiểu tóc ngắn, hai lớp tạo độ khối và thể hiện sự nữ tính, phù hợp với mặt trái xoan và độ dày trung bình của tóc"},{"name":"Cắt & tạo kiểu tóc “Chlying” (fishtail cut)","description":"Kiểu gọn, mềm mại với lớp chảy, thu hút ánh sáng và làm nổi bật khuôn mặt cân đối"}],"colors":[{"name":"Màu nâu caramel nhẹ","description":"Tón nâu nhẹ uyển chuyển, làm nổi bật tông da ấm giữa vùng mắt và cổ, tạo cảm giác tự nhiên và sang trọng"}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Tóc bob gói mìng","Tóc xanh dương pastel"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã có lịch sử thử nghiệm dịch vụ nail và nhiều dịch vụ diệt bệnh, combo tóc và nail cung cấp tiện ích và tăng giá trị giao dịch"}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có chuyên môn Hair Styling, Hair Color và đánh giá 5/5, phù hợp với nhu cầu thêm dịch vụ cô tạo kiểu và nhuộm"},"marketing_insight":"Khách hàng đã tích lũy 427 điểm (Gold) và thường xuyên sử dụng dịch vụ đa dạng. Đề nghị bán gói thẻ thành viên cao cấp (gồm 4 lần cắt & nhuộm, 2 lần phục hồi tóc) và cung cấp ưu đãi combo dịch vụ “Uốn tóc setting + Phục hồi tóc hư tổn” (ID 9 + 10) để tăng giá trị trung bình mỗi giao dịch. Thêm đề xuất dịch vụ “Detox body” vào lịch hẹn tiếp theo để tận dụng lịch sử sử dụng Detox."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:31:25.243' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (73, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:31:47.480' AS DateTime))
