INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (75, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan – cân đối, phù hợp với nhiều kiểu tóc có độ dài trung bình đến ngắn, tạo độ rộng ở phần trên hoặc tạo độ dài lớp để làm mềm góc cạnh.","hair_type":"Chất tóc tự nhiên, độ dày trung bình – dễ tạo kiểu, có thể uốn, nhuộm mà không gây hư tổn nghiêm trọng.","skin_tone":"Tông da trung bình sáng, tone ấm – phù hợp với các gam màu ấm, giúp da rạng rỡ hơn."},"recommendations":{"hairstyles":[{"name":"Bob lớp dài (Layered Bob)","description":"Kiểu bob có lớp nhẹ nhàng tạo độ phồng ở phần trên, cân bằng khuôn mặt trái xoan và tôn lên độ dày trung bình của tóc."},{"name":"Sóng nhẹ đôi bên (Soft Side Waves)","description":"Sóng nhẹ từ giữa tóc tới vai, giúp khuôn mặt tròn hơn một chút và tạo độ chuyển động tự nhiên cho tóc trung bình."}],"colors":[{"name":"Caramel Balayage","description":"Gam màu caramel ấm áp tạo độ sáng cho da, đồng thời giữ độ tự nhiên cho tóc tự nhiên, phù hợp với tone da ấm."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Balayage màu caramel","Bob lớp dài","Sóng nhẹ tự nhiên"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Tóc trung bình dày có thể uốn tạo độ phồng, tăng độ bồng bềnh cho kiểu bob hoặc sóng, đồng thời nâng giá trị dịch vụ."},{"service_id":8,"service_name":"Nhuộm tóc thời trang","reason":"Kết hợp màu Caramel Balayage vừa làm nổi bật tông da ấm vừa tăng giá trị trải nghiệm làm đẹp."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Sau uốn và nhuộm, việc phục hồi tóc giúp duy trì độ bóng, chắc khỏe, ngăn ngừa hư tổn lâu dài cho tóc đã qua nhiều lần xử lý."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên về Hair Styling & Hair Color, có đánh giá 5/5 và đã thực hiện thành công nhiều lần uốn + nhuộm cho khách hàng tương tự."},"marketing_insight":"Khách hàng Gia Kiên là thành viên Gold với 427 điểm, đã sử dụng đa dạng dịch vụ Spa và chăm sóc da, cho thấy xu hướng chi tiêu cao cho trải nghiệm toàn diện. Salon nên đề nghị gói thành viên ''Premium Hair Care'' bao gồm uốn, nhuộm và 2 lần phục hồi tóc mỗi tháng, cùng ưu đãi giảm 15% cho các dịch vụ chăm sóc da mặt, khuyến khích khách duy trì lịch hẹn hàng tháng và tăng tần suất mua combo tóc + nail."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:32:45.687' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (76, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan: Mặt có nét cân đối, phù hợp với hầu hết các kiểu tóc, đặc biệt là những kiểu cạnh nhọn và hơi tròn để tạo điểm nhấn.","hair_type":"Chất tóc tự nhiên, độ dày trung bình: Giữ  độ bền và bóng mà không cần bảo dưỡng quá mức.","skin_tone":"Tông da trung bình sáng (tone ấm): Thích hợp với màu sắc ấm như đỏ nâu, gạo núc, hoặc sóng vàng, giúp tôn lên sắc da."},"recommendations":{"hairstyles":[{"name":"Relaxed Layered Bob","description":"Kiểu tóc bob thả lỏng với các lớp kẻ, phù hợp với mặt trái xoan, tạo ấn tượng nhẹ nhàng mà vẫn đầy phong cách. Thích hợp cho tóc tự nhiên trung bình."},{"name":"Wavy Long Cut","description":"Kiểu tóc dài mềm mại, tạo sóng tự nhiên giúp làm nổi bật nét mặt tròn. Tốt cho tóc vừa từ trung bình tới dày, giúp tăng độ bóng và độ dày khi được xử lý đúng."}],"colors":[{"name":"Golden Honey","description":"Tông màu nhuộm vàng ấm, phù hợp với da ấm. Nhẹ nhàng nhưng vẫn rất nổi bật trên đầy tóc tự nhiên, phù hợp với phong cách tối giản và hiện đại."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Retro Curtain Layers","Soft Curls with Blowout Finish"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Với lịch sử phục hồi nhưng chưa có uốn thường xuyên, uốn setting giúp nâng tỉ lệ độ bền, sẵn sàng cho màu nhuộm Golden Honey và bảo vệ độ săn chắc, đồng thời tăng giá trị dịch vụ."},{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng đã trải nghiệm combo trước đây, gợi ý combo tóc và nail giúp nâng cao trải nghiệm làm đẹp toàn diện, tạo điểm nhấn hoàn hảo trên cả khuôn mặt và tay chân."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có chuyên môn Hair Styling & Hair Color, đánh giá 5/5, và đã được khách hàng thử nghiệm nhiều dịch vụ thành công. Thích hợp cho dịch vụ uốn & nhuộm."},"marketing_insight":"Gia Kiên đã trải nghiệm nhiều dịch vụ chăm sóc mêch không đánh giá cao, tuy nhiên tập trung vào massage và detox. Đề xuất bán thẻ thành viên lặp lại Monthly Salon Pack (chứa 1 lần massage, 1 lần phục hồi tóc, và 1 lần làm đẹp da mặt) để tăng tần số đặt lịch. Đưa ra ưu đãi 10% giảm giá khi đăng ký gói combo 3 lần trong 3 tháng kế tiếp, khuyến khích khách hàng sử dụng thêm dịch vụ bảo dưỡng và màu nhuộm."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:33:24.527' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (77, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T18:34:00.833' AS DateTime))
