INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (93, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan – dạng khuôn mặt cân đối, phù hợp với nhiều kiểu tóc từ layer nhẹ đến tóc dài tạo độ phồng ở đỉnh.","hair_type":"Chất tóc tự nhiên, độ dày trung bình – có khả năng giữ kiểu tốt, phù hợp với uốn nhẹ hoặc tạo lớp layer mà không gây quá tải.","skin_tone":"Tông da trung bình sáng, tone ấm – thích hợp với các tone màu ấm như vàng mật ong, nâu đất hoặc các màu pastel ấm."},"recommendations":{"hairstyles":[{"name":"Layer nhẹ tạo độ phồng ở đỉnh","description":"Lớp tóc ngắn trung bình kết hợp độ phồng nhẹ tại phần trên đầu, tôn lên đường nét cân đối của khuôn mặt trái xoan và tạo cảm giác trẻ trung."},{"name":"Bob dài lệch (Long Bob) với viền cánh","description":"Chiều dài vừa tới vai, cắt lệch một bên, tạo góc mềm mại cho khuôn mặt và phù hợp với chất tóc trung bình, dễ duy trì."}],"colors":[{"name":"Màu vàng mật ong (Honey Blonde)","description":"Tone ấm này làm nổi bật làn da sáng, đồng thời tạo chiều sâu cho tóc trung bình mà không làm tóc bão hòa."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Satin Waves – sóng satin lấp lánh","Soft Balayage – pha màu nhạt tự nhiên"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã thường xuyên dùng dịch vụ cắt tóc, nhuộm và massage; combo này cung cấp một buổi làm đẹp toàn diện, tăng giá trị đơn hàng lên 900.000đ và khuyến khích khách trải nghiệm dịch vụ nail cao cấp, phù hợp với hạng Gold."}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có đánh giá 5/5, chuyên môn Hair Styling & Hair Color, đã thực hiện nhiều lần nhuộm và cắt tóc cho khách, đồng thời hiểu rõ nhu cầu phục hồi và làm đẹp toàn diện."},"marketing_insight":"Khách hàng Gia Kiên đã tích lũy 427 điểm (hạng Gold) và thường xuyên dùng dịch vụ massage, detox và chăm sóc da. Đề nghị salon gửi voucher giảm 15% cho lần mua gói thành viên cao cấp (3 tháng) kèm ưu đãi miễn phí chăm sóc móng tay khi đặt combo tóc và nail, nhằm tăng tần suất ghé thăm và tối đa hoá giá trị trung bình mỗi lần ghé."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:01:00.630' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (94, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan – phù hợp với đa dạng kiểu tóc, nên lựa chọn các kiểu có độ cân bằng và nhẹ nhàng.","hair_type":"Chất tóc tự nhiên, độ dày trung bình – tóc không quá xơ yếu nên có thể chịu được các công đoạn nhuộm và uốn nhưng cần phục hồi định kỳ.","skin_tone":"Tông da trung bình sáng, tone ấm – màu da hoàn thiện nhất bằng phong cách ấm áp, tránh màu quá lạnh."},"recommendations":{"hairstyles":[{"name":"Mid-length bob with loose waves","description":"Độ dài vừa phải, rũ trải lên vai, tạo cảm giác nhẹ nhàng và hiện đại, phù hợp với hình tròn nhịp.\nCú pháp yếu tố: Uốn nhẹ (ID 9) có thể thực hiện bởi Stylist Linh Chi hoặc Stylist Hoàng Nam."},{"name":"Layered shoulder cut with side part","description":"Tạo độ năng động, lớp tóc nhẹ tạo độ dáng cho khuôn mặt, đồng thời giữ độ dày trung bình, không làm tóc mỏng thêm."}],"colors":[{"name":"Warm caramel highlights","description":"Màu caramel ấm tạo ánh sáng tự nhiên, làm nổi bật tông da sáng ấm mà không làm tóc quá đậm, phù hợp với tóc tự nhiên."}]},"trending":{"title":"Trend Tóc 2026: Natural Volume & Warm Tones","styles":["Layered bob with highlights","Soft curling with warm hues"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Tóc vừa dày vừa khỏe nhưng đã được phục hồi, nên uốn nhẹ để tạo kiểu nếp gọn, nâng cao vẻ hấp dẫn và bảo vệ tóc khỏi va công tác động mạnh."},{"service_id":14,"service_name":"Cấy tinh chất phục hồi","reason":"Lịch sử chịu nhiều liệu pháp thiệt hại (detox, massage, phục hồi), nên buổi cấy tinh chất sẽ củng cố sức khỏe tóc, giảm gãy rụng, tăng độ bóng."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có chuyên môn Hair Styling & Hair Color, đánh giá 5/5 và đã từng làm việc với thời trang tóc. Hàng ngày trong 3 ngày tới có lịch trình trống cho service uốn + màu sắc."},"marketing_insight":"Gia Kiên đã tích lũy 427 điểm Gold và lịch sử đa dạng dịch vụ, phản ánh sự trung thành cao. Đề xuất gửi thư khuyến mãi gói ''Membership Black'' gồm 3 buổi phục hồi + 2 buổi massage, ưu đãi 15% tương ứng. Sử dụng điểm để trừ giảm giá ở lần đặt cuối cùng, tăng khả năng lặp lại. Phân phối promo qua UMS SMS ngay hôm nay để kịp nhận vào tuần tới."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:02:41.693' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (95, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:06:02.990' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (96, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt dài, cần tạo độ rộng và cân bằng chiều dài bằng các đường cắt tạo lớp và bangs ngang","hair_type":"Tóc dày tự nhiên, hiện đang giữ độ ngắn, chịu tốt quá trình uốn và nhuộm","skin_tone":"Tông da sáng ấm, thích hợp với màu tóc ấm như vàng mật ong, caramel"},"recommendations":{"hairstyles":[{"name":"Bob lớp xoăn nhẹ (Layered Bob)","description":"Cắt tỉa lớp ngắn ở phần sau tạo độ dày, để phần trước dài hơn, giúp khuôn mặt dài trông cân đối hơn và tôn bật độ dày tự nhiên của tóc"},{"name":"Side‑swept Bangs + Lengthened Bob","description":"Bang lệch phía bên tạo độ rộng cho trán, kết hợp với độ dài tóc ở mức 2‑3 cm dài hơn để cân bằng tỷ lệ chiều dài mặt"}],"colors":[{"name":"Balayage mật ong (Honey Balayage)","description":"Sắc vàng mật ong ấm nhẹ kết hợp highlight caramel tạo độ sâu, tôn lên tông da sáng ấm và không làm mạnh quá độ dày tự nhiên của tóc"}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Bob lớp xoăn nhẹ","Balayage màu ấm","Bang lệch dài"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Tóc dày của khách chịu tốt uốn, tạo độ phồng và độ rộng cho khuôn mặt dài; dịch vụ giá cao giúp tăng doanh thu và nâng cấp trải nghiệm so với chỉ cắt & tạo kiểu"}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có đánh giá 5/5, chuyên môn Hair Styling & Hair Color, đã thực hiện nhiều lần nhuộm và cắt tóc cho khách, phù hợp với yêu cầu uốn + tạo kiểu cho tóc dày"},"marketing_insight":"Khách hàng là thành viên Gold với 427 điểm, thói quen sử dụng dịch vụ đa dạng (hair, massage, detox). Gợi ý bán thẻ thành viên VIP thêm 10% giảm giá cho mọi dịch vụ tóc và chăm sóc da, hoặc combo \"Hair + Nail\" (ID 17) để tăng tần suất ghé thăm và khai thác nhu cầu làm đẹp toàn diện."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:07:23.347' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (97, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Không thể xác định từ ảnh","hair_type":"Không thể xác định từ ảnh","skin_tone":"Tông da sáng trung bình ấm"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Không thể xác định từ ảnh và phù hợp chất tóc Không thể xác định từ ảnh."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da sáng trung bình ấm của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:10:10.450' AS DateTime))
