INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (106, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan – dáng mặt cân đối, phù hợp nhiều kiểu tóc dài, trung bình và lớp tóc tạo khối.","hair_type":"Tóc tự nhiên, độ dày trung bình, chưa có dấu hiệu hư tổn nặng.","skin_tone":"Tông da trung bình sáng, tone ấm, giúp tôn sáng những màu ấm và các tone caramel."},"recommendations":{"hairstyles":[{"name":"Bob dài lớp nhẹ (Long Bob Layer)","description":"Kiểu cắt dài tới vai với lớp nhẹ tạo độ bồng, phù hợp với khuôn mặt trái xoan, làm nổi bật đường hàm và gương mặt cân đối."},{"name":"Sóng hiện đại (Modern Waves)","description":"Tạo sóng nhẹ nhàng, độ bồng vừa phải, giúp cân bằng các góc của khuôn mặt và tăng phần năng động cho tóc trung bình dày."}],"colors":[{"name":"Caramel Gold","description":"Màu ấm, chút highlight caramel làm nổi bật tông da sáng ấm, đồng thời tạo chiều sâu cho tóc tự nhiên vừa dày."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Sóng biển (Beach Waves)","Cắt ngắn phồng (Volumized Pixie)"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã dùng dịch vụ cắt & tạo kiểu và nhuộm tóc thường xuyên; combo cung cấp dịch vụ nail cao cấp để tăng giá trị đơn hàng và tận dụng ưu đãi thành viên Gold."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Mặc dù tóc hiện tại chưa hư tổn nặng, nhưng lịch sử sử dụng nhiều nhuộm và uốn tạo nên nhu cầu duy trì sức khỏe tóc, giúp duy trì màu sắc và độ bóng."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có đánh giá 5/5, chuyên môn hair styling và color, phù hợp thực hiện uốn tóc setting kết hợp nhuộm Caramel Gold, đáp ứng nhu cầu làm mới kiểu tóc cho khách."},"marketing_insight":"Khách hàng thuộc hạng Gold với 427 điểm, đã trải nghiệm đa dạng dịch vụ spa và tóc. Đề xuất gói thành viên ''Gold Plus'' gồm ưu đãi 15% cho mọi dịch vụ hair & nail trong 3 tháng tới, cùng ưu đãi đặc biệt cho combo tóc và nail. Khi khách mua gói này, khả năng tăng chi tiêu trung bình lên 30% và duy trì tần suất ghé salon mỗi 2‑3 tuần."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:16:47.900' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (107, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:20:45.213' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (108, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (cân đối) – phù hợp với hầu hết các kiểu tóc dài, ngắn, hoặc trung bình, đặc biệt là các kiểu tạo độ phồng nhẹ và tạo đường nét góc mềm.","hair_type":"Tóc tự nhiên, độ dày trung bình – có khả năng giữ nếp tốt, dễ tạo lớp và chuyển màu.","skin_tone":"Tông da trung bình sáng, ấm – làm nổi bật các gam màu ấm như caramel, honey, óng ánh đồng."},"recommendations":{"hairstyles":[{"name":"Layered Bob dài (Bob lớp nhẹ)","description":"Kiểu bob dài lớp nhẹ giúp tôn lên đường hài hòa của khuôn mặt trái xoan, đồng thời tạo độ phồng ở phần gốc, phù hợp với tóc dày trung bình và dễ duy trì."},{"name":"Side‑swept bangs + tóc xõa nhẹ","description":"Rẽ ngực lệch một bên kết hợp tóc mái nhẹ sẽ làm khuôn mặt trông thon hơn, đồng thời tăng phần mềm mại cho gương mặt."}],"colors":[{"name":"Caramel Warm Balayage","description":"Gam màu caramel ấm kết hợp ánh sáng nhẹ giúp tôn lên tông da ấm của Gia Kiên, đồng thời giữ độ tự nhiên cho tóc trung bình."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Balayage mật ong","Bob lớp nhẹ","Mái lệch góc"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã từng dùng dịch vụ Cắt & tạo kiểu (ID7) và Nhuộm (ID8) nhiều lần. Combo này nâng cấp trải nghiệm với màu tóc mới (Caramel Warm Balayage) + nail cao cấp, tăng doanh thu và tạo cảm giác trọn gói sang trọng cho khách hạng Gold."},{"service_id":10,"service_name":"Phục hồi tóc hư tổn","reason":"Mặc dù tóc hiện tại trung bình, lịch sử có nhiều lần nhuộm và cấy tinh chất phục hồi, nên bổ sung điều trị phục hồi sẽ giữ độ bóng và chắc khỏe, đồng thời chuẩn bị cho màu mới."}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam là chuyên gia Hair Styling & Color với đánh giá 5/5, đã thực hiện nhiều lần nhuộm và cắt cho khách, hiểu rõ phong cách và mong muốn của Gia Kiên."},"marketing_insight":"Với 427 điểm Loyalty (hạng Gold) và tần suất đến salon hằng ngày, khách có tiềm năng mua gói thành viên VIP ưu đãi 10% cho mọi dịch vụ trong 6 tháng. Gợi ý gửi email khuyến mãi combo \"Hair + Nail + Skincare\" kèm phiếu giảm giá 150.000đ cho dịch vụ Phục hồi tóc hư tổn, khuyến khích khách đăng ký gói chăm sóc tóc định kỳ (3 lần/phần) để tăng giá trị sống lâu dài."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:21:43.463' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (109, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu."}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:22:45.343' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (110, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Khuôn mặt trái xoan, cân đối, phù hợp với hầu hết các kiểu tóc dài và ngắn, đặc biệt là các độ dài trung bình đến ngắn với độ tạo khối nhẹ.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, không có dấu hiệu hư tổn nghiêm trọng nhưng đã từng thực hiện nhiều lần nhuộm và cấy tinh chất phục hồi.","skin_tone":"Tông da trung bình sáng, ấm, giúp tôn lên các màu tóc ấm như vàng, nâu caramel và các tone trung tính."},"recommendations":{"hairstyles":[{"name":"Layered Bob dài vừa (Lớp ngắn trung bình)","description":"Kiểu cắt bob lớp nhẹ giúp làm nổi bật đường nét khuôn mặt trái xoan, tạo cảm giác gọn gàng, đồng thời tăng khối lượng cho tóc trung bình mà không làm tóc bị nặng."},{"name":"Soft Waves dài tới vai (Sóng nhẹ)","description":"Sóng nhẹ nhàng mang lại độ bồng bềnh mà vẫn giữ được sự tự nhiên cho tóc dày vừa, phù hợp với tông da ấm và tạo vẻ trẻ trung, năng động."}],"colors":[{"name":"Caramel Warm (Nâu caramel ấm)","description":"Màu caramel ấm giúp làm nổi bật tông da ấm của khách, đồng thời tạo chiều sâu và ánh sáng tự nhiên cho tóc trung bình."},{"name":"Honey Blonde (Vàng mật ong)","description":"Tone vàng mật ong tăng cường ánh sáng trên tóc, phù hợp với khuôn mặt trái xoan và làm da trông rạng rỡ hơn."}]},"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Beach Waves tự nhiên","Bob lớp ngắn đa lớp","Balayage hơi sáng màu ấm"]},"upsell":[{"service_id":9,"service_name":"Uốn tóc setting","reason":"Khách đã thực hiện nhiều lần nhuộm và cấy tinh chất phục hồi, nên bổ sung uốn tóc setting sẽ tạo độ bồng, giấc cho kiểu Soft Waves, tăng giá trị dịch vụ và đồng thời duy trì độ chắc khỏe sau khi kết hợp với phục hồi."}],"booking_suggestion":{"recommended_service_id":9,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có đánh giá 5/5, chuyên môn Hair Styling & Hair Color, đã từng thực hiện các dịch vụ nhuộm và cắt tóc cho khách, phù hợp nhất để thực hiện uốn tóc setting và phối màu đề xuất."},"marketing_insight":"Với 427 điểm Loyalty (hạng Gold) và lịch sử sử dụng đa dạng dịch vụ spa, khách hàng có xu hướng chi tiêu cho các combo chăm sóc toàn diện. Salon nên đề xuất gói thành viên Gold Plus, cho phép giảm 10% cho mọi dịch vụ Hair (Uốn, Nhuộm, Phục hồi) và tặng một buổi chăm sóc da mặt cơ bản miễn phí mỗi 3 tháng, khuyến khích khách mua gói combo Hair + Spa (Combo tóc và nail) để tăng doanh thu trung bình mỗi lượt đến salon."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:23:34.377' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (111, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (cân đối, phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình, chưa gặp vấn đề nghiêm trọng lợi nhuận tóc","skin_tone":"Tông da trung bình sáng (tone ấm)"},"recommendations":{"hairstyles":[{"name":"Cắt & tạo kiểu tóc (ID 7)","description":"Kiểu tóc kim loại ngắn nhẹ nhàng (bob) thoáng khí, phù hợp với dạng mặt trái xoan và tóc trung bình, tạo cảm giác săn chắc và hiện đại."},{"name":"Uốn tóc setting (ID 9)","description":"Tóc mềm, lệch nhẹ, tạo khối lượng và độ phồng tự nhiên, phù hợp với tóc trung bình và thẩm mỹ xuyên ga mặt."}],"colors":[{"name":"Nhuộm tóc thời trang (ID 8)","description":"Màu nâu caramel hoặc gốm sương nhẹ giúp làm nổi bật tông da ấm, hợp với phong cách hiện đại và dịu nhẹ."}],"trending":{"title":"Xu hướng tóc mùa Hè 2026","styles":["Cắt mọc ngắn 3D","Tóc thẳng nhẹ tự nhiên"]}},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách đã từng thử nhiều dịch vụ làm tóc và nhãn tay gần đây. Combo này kết hợp chăm sóc tóc (cắt/định hình + màu sắc) và nail cao cấp, tăng giá trị dịch vụ và khuyến khích khách sử dụng khi có điểm loyalty cao."},{"service_id":3,"service_name":"Massage cổ vai gáy","reason":"Với lịch sử sử dụng nhiều dịch vụ massage, khách có thể muốn giảm căng thẳng và thư giãn thêm sau công việc làm tóc."}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam chuyên môn Hair Styling & Hair Color, đánh giá 5/5, đã từng làm dịch vụ ‘Cắt & tạo kiểu tóc’ và ‘Nhuộm tóc thời trang’ cho khách hàng, luôn được đánh giá cao và có ca trực trong 3 ngày tới."},"marketing_insight":"Gia Kiên đã tích lũy 427 điểm, hạng Gold. Khách hàng thường xuyên thử nghiệm nhiều dịch vụ mà kết quả chưa được đánh giá; đề xuất chương trình mua thẻ thành viên cao cấp (điểm cộng gấp 2 lần) để khuyến khích đăng ký gói Combo tóc & nail; nội dung nhấn mạnh ưu đãi 10% khi mua thêm trị liệu da đầu hoặc phục hồi tóc lần đầu."}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:24:51.790' AS DateTime))
INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (112, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan (Cân đối phù hợp nhiều kiểu tóc)","hair_type":"Chất tóc tự nhiên, độ dày trung bình","skin_tone":"Tông da trung bình sáng (Tone ấm)"},"recommendations":{"hairstyles":[{"name":"Tóc uốn xoăn nhẹ lãng mạn","description":"Kiểu tóc giúp che khuyết điểm khuôn mặt Trái xoan (Cân đối phù hợp nhiều kiểu tóc) và phù hợp chất tóc Chất tóc tự nhiên, độ dày trung bình."}],"colors":[{"name":"Màu nâu trà sữa trẻ trung","description":"Tông màu nhuộm cực kỳ nịnh tông da Tông da trung bình sáng (Tone ấm) của bạn."}]},"trending":{"title":"Trending Hè 2026","styles":["Màu trà sữa mật ong","Cắt layer tầng bồng bềnh"]},"upsell":[{"service_id":8,"service_name":"Combo Nhuộm thời trang + Phục hồi tóc hư tổn","reason":"Đổi mới phong cách với màu nhuộm tôn da sáng, kết hợp hấp collagen để bảo vệ biểu bì tóc."}],"booking_suggestion":{"recommended_service_id":8,"suggested_stylist_id":2,"reason":"Stylist Linh Chi chuyên uốn tạo kiểu và nhuộm màu phục hồi, được đánh giá cao (5/5 sao)."},"marketing_insight":"Khách hàng Gia Kiên tích lũy được 427 điểm, đề xuất tặng thêm combo dầu gội phục hồi tại nhà để tăng gắn kết thương hiệu.","image_url":"data:image/jpeg;base64,"}', N'rule-based-fallback', 1800, 1000, CAST(0.0000 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:29:36.837' AS DateTime))
