INSERT [dbo].[AIAuditLogs] ([AuditId], [UserId], [FeatureName], [Prompt], [AIResponse], [ModelName], [InputToken], [OutputToken], [Cost], [IsChecked], [CheckResult], [CreatedAt]) VALUES (117, 98, N'AI Stylist Advisor', N'Phân tích ảnh chân dung khách hàng CustomerId 82', N'{"analysis":{"face_shape":"Trái xoan, có độ cân đối cao nên phù hợp với đa dạng kiểu tóc, từ dài tới trung bình, các lớp hơi tròn nhẹ.","hair_type":"Chất tóc tự nhiên, độ dày trung bình, không quá mỏng. Bạn đang có lịch sử phục hồi Tinh chất và cần bảo vệ sức khỏe tóc.","skin_tone":"Tông da trung bình sáng (tone ấm) nên các màu tóc ấm sẽ nhấn lên làn da."},"recommendations":{"hairstyles":[{"name":"Cắt & tạo kiểu tóc chậm dở hơi (soft layered bob)","description":"Kiểu tóc hở môi, dài đến vai, tạo bóng mượt cho mái tóc tự nhiên và phù hợp với khuôn mặt trái xoan."},{"name":"Lưng ngắn (chignon) nhẹ với lớp dương trú","description":"Tạo sự thanh lịch, phù hợp với da ấm, giữ bình độ bóng và giúp khôi phục tóc khỏe mạnh hơn."}],"colors":[{"name":"Brown caramel","description":"Màu nâu dầm, ấm áp, huyền ấm hương, làm nổi bật tông da trung bình sáng và tăng độ bóng cho tóc đã được phục hồi."}]},"trending":{"title":"Xu hướng tóc mùa hè 2026","styles":["Mini buzz cut","Layered texture waves"]},"upsell":[{"service_id":17,"service_name":"Combo tóc và nail","reason":"Khách hàng đã có lịch sử phục hồi tóc và là Gold Loyalty, combo này giúp tăng giá trị chi tiêu, cải thiện sức khỏe tóc và nail trong một buổi liệu trình."}],"booking_suggestion":{"recommended_service_id":17,"suggested_stylist_id":9,"reason":"Stylist Hoàng Nam có chuyên môn Hair Styling & Hair Color, đánh giá 5/5 và đã làm phục hồi tóc trong lịch sử, nên phù hợp cho session cao cấp này."},"marketing_insight":"Gia Kiên thuộc hạng Gold với 427 điểm, thường chọn các dịch vụ cao cấp và có thói quen quay lại các dịch vụ Spa. Đề xuất gói thành viên ‘Premium Care’ mỗi 3 tháng bao gồm 2 lần phục hồi tóc + 1 lần massage đá nóng, giúp tăng tần suất phục vụ 30% và chuyển đổi quy mô khách thành viên trung bình.","image_url":"data:image/jpeg;base64,"}', N'gemini-2.5-flash', 1800, 1000, CAST(0.0180 AS Decimal(18, 4)), 0, NULL, CAST(N'2026-06-27T19:33:26.880' AS DateTime))
