INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (59, 101, N'Tu van cho toi dich vu lam mong', N'😊 Cảm ơn bạn đã liên hệ! Hiện tại hệ thống AI đang bảo trì. Bạn có thể xem danh sách dịch vụ và đặt lịch trực tiếp trên hệ thống.', CAST(N'2026-06-20T18:53:50.760' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (60, 101, N'Tu van giup em lam mong', N'Chào bạn! 😊 Về dịch vụ làm móng, Beauty Salon có 3 lựa chọn tuyệt vời cho bạn:

- **Sơn gel Hàn Quốc**: 180.000đ (40 phút) - Màu sắc bóng đẹp tự nhiên.
- **Chăm sóc móng tay chân**: 220.000đ (50 phút) - Làm sạch và dưỡng móng chuyên sâu.
- **Nail cao cấp**: 250.000đ (45 phút) - Làm móng gel bền màu, sang trọng.

Bạn muốn chọn dịch vụ nào để em hướng dẫn đặt lịch ạ? ✨', CAST(N'2026-06-20T18:55:06.500' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (61, 101, N'có', N'Dạ, vậy bạn muốn chọn dịch vụ làm móng nào trong 3 lựa chọn trên ạ? 😊 

Sau khi bạn chọn xong, bạn hãy vào mục **"Đặt lịch hẹn"** trên menu → Chọn dịch vụ → Chọn ngày giờ và kỹ thuật viên để hoàn tất đặt lịch nhé! ✨', CAST(N'2026-06-20T18:56:05.340' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (62, 101, N'lựa chọn 1', N'Dạ, bạn chọn **Sơn gel Hàn Quốc** với giá **180.000đ** và thời gian thực hiện khoảng **40 phút** đúng không ạ? ✨

Để đặt lịch, bạn vui lòng vào mục **"Đặt lịch hẹn"** trên menu → Chọn dịch vụ này → Chọn ngày giờ và kỹ thuật viên bạn yêu thích để xác nhận nhé! 😊', CAST(N'2026-06-20T18:56:30.790' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (63, 101, N'đề xuất ra giúp tôi', N'Vì bạn đang quan tâm đến làm đẹp, em xin đề xuất cho bạn một số combo và dịch vụ kết hợp để bạn được thư giãn toàn diện hơn nhé:

✨ **Combo tóc và nail (Spa Combo)**: 900.000đ (150 phút) - Đây là lựa chọn tuyệt vời để bạn làm đẹp cả tóc và móng trong một lần ghé thăm.
✨ **Combo thư giãn cuối tuần (Spa Combo)**: 850.000đ (120 phút) - Kết hợp Massage body và chăm sóc da mặt, giúp bạn xả stress cực hiệu quả.

Nếu bạn chỉ muốn làm lẻ, bạn có thể chọn thêm **Chăm sóc da mặt cơ bản** (350.000đ - 60 phút) để làn da tươi tắn hơn. Bạn thấy những gợi ý này thế nào ạ? 😊', CAST(N'2026-06-20T18:56:55.467' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (64, 101, N'nên chọn kỹ thuật viên nào', N'Dạ, hiện tại mỗi kỹ thuật viên bên em đều có tay nghề cao và phong cách làm việc chuyên nghiệp ạ. 😊

Để chọn được người phù hợp nhất, bạn vui lòng vào mục **"Đặt lịch hẹn"** trên menu. Tại bước chọn kỹ thuật viên, hệ thống sẽ hiển thị danh sách các bạn đang trống lịch cùng với đánh giá từ những khách hàng trước đó để bạn dễ dàng lựa chọn theo ý muốn nhé! ✨', CAST(N'2026-06-20T18:57:25.310' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (65, 101, N'tôi muốn kỹ thuật viên tốt nhất''', N'Dạ, em hiểu ạ! 😊 Vì mỗi kỹ thuật viên tại Beauty Salon đều được đào tạo bài bản và có thế mạnh riêng, nên "tốt nhất" sẽ tùy vào nhu cầu của bạn.

Để chọn được kỹ thuật viên xuất sắc nhất, bạn vui lòng vào mục **"Đặt lịch hẹn"** trên menu. Tại bước chọn kỹ thuật viên, bạn hãy xem phần **đánh giá (stars) và nhận xét** từ các khách hàng trước đó để chọn người có chuyên môn phù hợp nhất với mong muốn của mình nhé! ✨', CAST(N'2026-06-20T18:57:49.433' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (66, 101, N'TToi muon uon toc xoan thi co nhung dich vu nao?', N'Dạ, nếu bạn muốn uốn tóc xoăn, Beauty Salon có dịch vụ **Uốn tóc setting** rất phù hợp ạ:

✨ **Uốn tóc setting**: 850.000đ, 120 phút - Giúp tóc giữ nếp lâu, tạo độ bồng bềnh và phù hợp với nhiều phong cách khác nhau.
[Đặt lịch: Uốn tóc setting | 9]

Để đặt lịch, bạn vui lòng vào mục **"Đặt lịch hẹn"** trên menu → Chọn dịch vụ này → Chọn ngày giờ và kỹ thuật viên để xác nhận nhé! 😊', CAST(N'2026-06-20T19:00:36.360' AS DateTime))
