INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (69, 99, N'tôi muốn đặt lịch', N'Chào bạn! 😊 Rất vui được hỗ trợ bạn đặt lịch làm đẹp.

Để đặt lịch, bạn vui lòng thực hiện theo các bước sau nhé: 
Vào menu **"Đặt lịch hẹn"** $\rightarrow$ **Chọn dịch vụ** $\rightarrow$ **Chọn ngày giờ** $\rightarrow$ **Chọn kỹ thuật viên** $\rightarrow$ **Xác nhận**.

Nếu bạn cần tư vấn chọn dịch vụ phù hợp, hãy cho mình biết nhu cầu của bạn nhé! ✨', CAST(N'2026-06-20T19:04:13.900' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (70, 99, N'tôi muốn làm nail', N'Chào bạn! ✨ Bên mình có 3 lựa chọn làm nail tuyệt vời để bạn tham khảo nhé:

- **Sơn gel Hàn Quốc**: 180.000đ (40 phút) - Màu sắc tự nhiên, bóng đẹp. [Đặt lịch: Sơn gel Hàn Quốc | 5]
- **Chăm sóc móng tay chân**: 220.000đ (50 phút) - Làm sạch, dưỡng móng và da. [Đặt lịch: Chăm sóc móng tay chân | 6]
- **Nail cao cấp**: 250.000đ (45 phút) - Làm móng gel cao cấp, bền màu. [Đặt lịch: Nail cao cấp | 4]

Bạn thích phong cách nào nhất ạ? Nếu muốn kết hợp làm tóc luôn, bạn có thể chọn [Đặt lịch: Combo tóc và nail | 17] với giá 900.000đ (150 phút) nhé! 💅💖', CAST(N'2026-06-20T19:04:49.710' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (71, 99, N'nên chọn kỹ thuật viên nào cho nail', N'💅 Với dịch vụ nail, bạn có thể chọn Nail cao cấp, thời lượng khoảng 45 phút. Bạn nên đặt lịch trước để chọn được kỹ thuật viên phù hợp.', CAST(N'2026-06-20T19:05:22.253' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (72, 99, N'tôi muốn massage', N'Chào bạn! 😊 Nếu bạn muốn massage để thư giãn và giảm căng thẳng, bên mình có các dịch vụ chuyên sâu sau đây:

- **Massage cổ vai gáy**: 250.000đ (45 phút) - Giúp giảm đau mỏi vùng cổ và vai. [Đặt lịch: Massage cổ vai gáy | 3]
- **Massage đá nóng**: 450.000đ (75 phút) - Trị liệu bằng đá nóng giúp lưu thông máu và thư giãn sâu. [Đặt lịch: Massage đá nóng | 2]

Bạn muốn tập trung giảm đau mỏi vùng cổ vai gáy hay muốn thư giãn toàn thân với đá nóng ạ? ✨', CAST(N'2026-06-20T19:05:59.020' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (73, 99, N'massag có những ký thuật viên nào', N'Chào bạn! 😊 Về danh sách kỹ thuật viên cho dịch vụ massage, bạn vui lòng thực hiện các bước sau để xem chi tiết nhé:

Vào menu **"Đặt lịch hẹn"** $\rightarrow$ **Chọn dịch vụ massage bạn muốn** $\rightarrow$ Hệ thống sẽ hiển thị **danh sách các kỹ thuật viên** còn trống lịch để bạn lựa chọn ạ. ✨

Bạn muốn chọn Massage cổ vai gáy [Đặt lịch: Massage cổ vai gáy | 3] hay Massage đá nóng [Đặt lịch: Massage đá nóng | 2] để mình hướng dẫn chi tiết hơn? 💆‍♀️', CAST(N'2026-06-20T19:06:19.220' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (74, 99, N'gợi ý kỹ thuật viên trong massgae cổ vai gáy', N'Chào bạn! 😊 Vì danh sách kỹ thuật viên sẽ thay đổi theo thời gian thực dựa trên lịch trống, bạn vui lòng thực hiện các bước sau để chọn kỹ thuật viên phù hợp nhất nhé:

Vào menu **"Đặt lịch hẹn"** $\rightarrow$ Chọn [Đặt lịch: Massage cổ vai gáy | 3] $\rightarrow$ Hệ thống sẽ hiển thị danh sách các kỹ thuật viên đang sẵn sàng cùng với đánh giá từ khách hàng để bạn dễ dàng lựa chọn ạ. ✨

Chúc bạn có những giây phút thư giãn tuyệt vời tại salon! 💆‍♀️', CAST(N'2026-06-20T19:06:49.703' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (75, 99, N'ngày 22 còn chỗ trống cho massage đá nóng không', N'Chào bạn! 😊 Để kiểm tra chính xác các khung giờ còn trống cho dịch vụ **Massage đá nóng** vào ngày 22, bạn vui lòng thực hiện các bước sau nhé:

