INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (76, 99, N'như cặc', N'Chào bạn, Beauty Salon luôn mong muốn mang lại trải nghiệm tốt nhất cho khách hàng. Nếu có điều gì khiến bạn không hài lòng, bạn vui lòng chia sẻ cụ thể để salon lắng nghe và cải thiện chất lượng dịch vụ tốt hơn nhé! 😊✨', CAST(N'2026-06-20T19:08:37.660' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (77, 99, N'bạn biết nhậu không', N'😊 Cảm ơn bạn đã liên hệ! Hiện tại hệ thống AI đang bảo trì. Bạn có thể xem danh sách dịch vụ và đặt lịch trực tiếp trên hệ thống.', CAST(N'2026-06-20T19:08:51.157' AS DateTime))
