INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (177, 101, N'đặt lịch', N'Dạ, tôi rất sẵn lòng hỗ trợ bạn đặt lịch ạ! 😊

Để tôi có thể hiển thị các khung giờ trống chính xác nhất, bạn vui lòng cho tôi biết:
1. **Dịch vụ** bạn muốn làm là gì? (Ví dụ: Massage, Uốn tóc, Nail, Skincare...)
2. **Ngày** bạn dự định đến salon?
3. Bạn có yêu cầu chọn **kỹ thuật viên/stylist** cụ thể nào không ạ?

Hoặc nếu bạn muốn tự chọn, bạn có thể vào mục **"Đặt lịch hẹn"** trên menu chính nhé! 🌸', CAST(N'2026-06-22T19:17:34.820' AS DateTime))
INSERT [dbo].[AIChatLogs] ([ChatId], [UserId], [Question], [Answer], [CreatedAt]) VALUES (178, 101, N'đặt lịch với kỹ thuật viên tốt nhất', N'Dạ, để chọn kỹ thuật viên tốt nhất, bạn có thể tham khảo chị **Linh Chi (Kỹ thuật viên Massage)** hoặc anh **Quốc Bảo (Tạo mẫu tóc)** và anh **Hoàng Nam (Barber/Stylist)**, đây là những chuyên gia có đánh giá 5/5 sao từ khách hàng ạ! ⭐

Tuy nhiên, vì mỗi kỹ thuật viên có chuyên môn khác nhau, bạn vui lòng cho tôi biết bạn muốn làm **dịch vụ nào** (ví dụ: Massage, Cắt tóc hay Chăm sóc da) để tôi tư vấn người phù hợp nhất và hiển thị giờ trống cho bạn nhé! 😊

Nếu bạn muốn đặt lịch ngay, hãy cho tôi biết tên dịch vụ và ngày bạn muốn đến ạ. 🌸', CAST(N'2026-06-22T19:17:59.050' AS DateTime))
