INSERT [dbo].[TreatmentNotes] ([NoteId], [AppointmentId], [EmployeeId], [Title], [Content], [NoteType], [ProductsUsed], [SkinCondition], [Technique], [CustomerFeedback], [Recommendation], [FollowUpDate], [ProgressStatus], [CreatedAt], [UpdatedAt], [PersonalNotes], [SpecialNotice]) VALUES (15, 177, 1, N'Ghi chú ca trị liệu - Nguyễn Thị Thanh Mai', N'Khách hàng hoàn thành buổi thứ 4 trong liệu trình chăm sóc móng VIP.', N'General Notes', N'Son gel OPI - Bubble Bath, Top Coat OPI - Top Coat, Dưỡng móng OPI - Nail Oil', N'1. Form móng oval buổi trước vẫn giữ form tốt
2. Móng tay cứng cáp hơn, ít giòn gãy
3. Lớp sơn cũ mọc dài ra 2mm
4. Da quanh móng hơi khô ráp nhẹ', N'1. Loại bỏ lớp sơn gel cũ nhẹ nhàng bằng gel remover chuyên dụng
2. Cắt tỉa da sạch sẽ, dũa lại form móng oval chuẩn
3. Sơn base coat liên kết móng chất lượng cao
4. Sơn 2 lớp gel OPI màu Bubble Bath
5. Sơn top coat khóa màu siêu bóng bảo vệ móng
6. Massage tay bằng tinh dầu dưỡng OPI Nail Oil', N'1. Màu sơn bóng đẹp không bị bọt khí
2. Khách cực kỳ ưng ý màu hồng nhạt Bubble Bath
3. Da quanh móng mềm mại sau khi massage tinh dầu
4. Khách đồng ý tái khám sau 3 tuần', N'1. Tránh rửa chén hoặc làm việc tiếp xúc với hóa chất tẩy rửa mạnh
2. Thoa kem dưỡng ẩm tay hằng ngày
3. Thoa tinh dầu dưỡng móng 2-3 lần một tuần
4. Quay lại tiệm tái khám và chăm sóc định kỳ sau 3 tuần', CAST(N'2026-07-19' AS Date), N'IN_PROGRESS', CAST(N'2026-06-28T16:58:28.540' AS DateTime), CAST(N'2026-06-28T17:00:02.863' AS DateTime), N'Khách hàng Nguyễn Thị Thanh Mai thích màu hồng pastel nhẹ nhàng thanh lịch, thích vẽ họa tiết hoa nhí. Hãy tư vấn mẫu này cho buổi tiếp theo.', N'Khách hàng nhạy cảm với nước sơn gel giá rẻ, cần dùng sơn OPI cao cấp chính hãng.')
INSERT [dbo].[TreatmentNotes] ([NoteId], [AppointmentId], [EmployeeId], [Title], [Content], [NoteType], [ProductsUsed], [SkinCondition], [Technique], [CustomerFeedback], [Recommendation], [FollowUpDate], [ProgressStatus], [CreatedAt], [UpdatedAt], [PersonalNotes], [SpecialNotice]) VALUES (16, 179, 2, N'Treatment Note', N'Khách hàng hài lòng với mẫu nail hiện tại, màu sắc phù hợp với tông da. Móng chắc khỏe, không bị hư tổn. Tiếp tục duy trì liệu trình.', N'General Notes', N'Son gel OPI - Bubble Bath, Top Coat OPI - Top Coat, Dưỡng móng OPI - Nail Oil', N'Móng hơi giòn, dễ gãy ở đầu móng
Da quanh móng hơi khô
Màu móng cũ đã phai
Không có dấu hiệu nấm hay viêm', N'1. Làm sạch móng và da tay
2. Cắt da, dũa form móng oval
3. Sơn base coat bảo vệ
4. Sơn gel màu hồng nhạt (2 lớp)
5. Vẽ nail art hoa nhỏ ở ngón áp út
6. Sơn top coat bóng
7. Dưỡng da và massage tay', N'Móng đẹp, màu sắc đều và bóng
Nail art tinh tế, khách hàng rất hài lòng
Da tay mềm mịn sau massage
Hướng dẫn chăm sóc tại nhà đầy đủ', N'Giữ móng khô ráo, đeo găng tay khi làm việc nhà
Dưỡng móng 2-3 lần/tuần bằng nail oil
Tránh sử dụng hóa chất mạnh
Tái khám sau 3-4 tuần', NULL, N'IN_PROGRESS', CAST(N'2026-06-28T17:26:49.853' AS DateTime), CAST(N'2026-06-28T17:45:28.423' AS DateTime), N'Khách hàng rất thích màu hồng và phong cách nhẹ nhàng. Nên tư vấn thêm các mẫu nail tông pastel.', N'Khách hàng dị ứng với sản phẩm có mùi nồng.')
